def seed_categories(db):
    """创建分类体系"""
    categories = [
        {"name": "Apparel", "slug": "apparel", "level": 1, "sort_order": 1},
        {"name": "Footwear", "slug": "footwear", "level": 1, "sort_order": 2},
        {"name": "Bags", "slug": "bags", "level": 1, "sort_order": 3},
        {"name": "Athleisure", "slug": "athleisure", "level": 2, "parent_slug": "apparel", "sort_order": 1},
        {"name": "Outdoor", "slug": "outdoor-apparel", "level": 2, "parent_slug": "apparel", "sort_order": 2},
        {"name": "Performance Athletic", "slug": "performance-athletic", "level": 2, "parent_slug": "apparel", "sort_order": 3},
        {"name": "Running Shoes", "slug": "running-shoes", "level": 2, "parent_slug": "footwear", "sort_order": 1},
        {"name": "Casual/Sandals", "slug": "casual-sandals", "level": 2, "parent_slug": "footwear", "sort_order": 2},
        {"name": "Lifestyle Sneakers", "slug": "lifestyle-sneakers", "level": 2, "parent_slug": "footwear", "sort_order": 3},
        {"name": "Travel Luggage", "slug": "travel-luggage", "level": 2, "parent_slug": "bags", "sort_order": 1},
        {"name": "Everyday Backpacks", "slug": "everyday-backpacks", "level": 2, "parent_slug": "bags", "sort_order": 2},
        {"name": "Everyday/Totes", "slug": "everyday-totes", "level": 2, "parent_slug": "bags", "sort_order": 3},
    ]

    cat_map = {}
    # Create top-level categories first
    for c in categories:
        if c["level"] == 1:
            existing = db.query(Category).filter(Category.slug == c["slug"]).first()
            if not existing:
                cat = Category(
                    name=c["name"],
                    slug=c["slug"],
                    level=c["level"],
                    sort_order=c["sort_order"],
                )
                db.add(cat)
                db.flush()
                cat_map[c["slug"]] = cat
            else:
                cat_map[c["slug"]] = existing

    # Create sub-categories
    for c in categories:
        if c["level"] == 2:
            existing = db.query(Category).filter(Category.slug == c["slug"]).first()
            if not existing:
                parent = cat_map.get(c["parent_slug"])
                cat = Category(
                    name=c["name"],
                    slug=c["slug"],
                    parent_id=parent.id if parent else None,
                    level=c["level"],
                    sort_order=c["sort_order"],
                )
                db.add(cat)
                db.flush()
                cat_map[c["slug"]] = cat
            else:
                cat_map[c["slug"]] = existing

    return cat_map


def seed_brands(db, cat_map):
    """创建品牌和品牌-分类关联"""
    # 子分类映射
    brand_subcat = {
        # 服饰品牌
        "Lululemon": "athleisure",
        "Nike": "performance-athletic",
        "Adidas (北美)": "performance-athletic",
        "Under Armour": "performance-athletic",
        "Athleta (Gap Inc.)": "athleisure",
        "Alo Yoga": "athleisure",
        "Vuori": "athleisure",
        "Outdoor Voices": "athleisure",
        "Gymshark": "performance-athletic",
        "Fabletics": "athleisure",
        "Rhone": "athleisure",
        "Ten Thousand": "performance-athletic",
        "Patagonia": "outdoor-apparel",
        "The North Face": "outdoor-apparel",
        "Arc'teryx": "outdoor-apparel",
        "Columbia": "outdoor-apparel",
        # 鞋履品牌
        "New Balance": "lifestyle-sneakers",
        "Hoka": "running-shoes",
        "On Running": "running-shoes",
        "Brooks": "running-shoes",
        "Allbirds": "lifestyle-sneakers",
        "Crocs": "casual-sandals",
        "Birkenstock (北美)": "casual-sandals",
        # 箱包品牌
        "Herschel Supply Co.": "everyday-backpacks",
        "Away": "travel-luggage",
        "Dagne Dover": "everyday-totes",
        "Bellroy": "everyday-backpacks",
        "Tumi": "travel-luggage",
        "Peak Design": "everyday-backpacks",
        "JanSport": "everyday-backpacks",
    }

    brand_map = {}
    for data in BRANDS_DATA:
        existing = db.query(Brand).filter(Brand.slug == data["slug"]).first()
        if existing:
            brand_map[data["name"]] = existing
            continue

        brand = Brand(
            name=data["name"],
            slug=data["slug"],
            country=data["country"],
            founded_year=data["founded_year"],
            parent_company=data.get("parent_company"),
            headquarters=data.get("headquarters"),
            website=data.get("website"),
            description=data.get("description"),
            is_active=True,
        )
        db.add(brand)
        db.flush()

        # 创建品牌-分类关联
        main_cat_slug = data.get("category", "").lower()
        sub_cat_slug = brand_subcat.get(data["name"])

        # 关联主分类
        main_cat = cat_map.get(main_cat_slug)
        if main_cat:
            bc = BrandCategory(
                brand_id=brand.id,
                category_id=main_cat.id,
                is_primary=True,
            )
            db.add(bc)

        # 关联子分类
        if sub_cat_slug:
            sub_cat = cat_map.get(sub_cat_slug)
            if sub_cat:
                bc = BrandCategory(
                    brand_id=brand.id,
                    category_id=sub_cat.id,
                    is_primary=False,
                )
                db.add(bc)

        brand_map[data["name"]] = brand

    return brand_map


def seed_dimension_data(db, brand_map):
    """填充各维度的数据 - 数据更新至 2026-07-01"""
    for data in BRANDS_DATA:
        brand = brand_map[data["name"]]

        # 1. Brand Positioning
        pos = data.get("positioning")
        if pos:
            existing = db.query(BrandPositioning).filter(BrandPositioning.brand_id == brand.id).first()
            if not existing:
                bp = BrandPositioning(
                    brand_id=brand.id,
                    price_tier=pos["price_tier"],
                    brand_tone=pos["brand_tone"],
                    core_value_proposition=pos["core_value_proposition"],
                    usp=pos["usp"],
                    brand_story=pos["brand_story"],
                    source_type="manual",
                )
                db.add(bp)

        # 2. Pricing Strategy
        pricing_list = data.get("pricing", [])
        existing_count = db.query(PricingStrategy).filter(PricingStrategy.brand_id == brand.id).count()
        if existing_count == 0:
            for p in pricing_list:
                ps = PricingStrategy(
                    brand_id=brand.id,
                    category_name=p["category_name"],
                    price_range_min=p["price_range_min"],
                    price_range_max=p["price_range_max"],
                    avg_price=p["avg_price"],
                    discount_frequency=p["discount_frequency"],
                    typical_discount_pct=p["typical_discount_pct"],
                    has_membership=p.get("has_membership", False),
                    membership_price=p.get("membership_price") if p.get("has_membership") else None,
                    membership_model=p.get("membership_model"),
                    data_as_of=date(2026, 7, 1),
                    source_type="manual",
                )
                db.add(ps)

        # 3. Target Demographics
        demo = data.get("demographics")
        if demo:
            existing = db.query(TargetDemographics).filter(TargetDemographics.brand_id == brand.id).first()
            if not existing:
                td = TargetDemographics(
                    brand_id=brand.id,
                    age_range=demo["age_range"],
                    gender_skew=demo["gender_skew"],
                    income_level=demo["income_level"],
                    lifestyle_tags=demo["lifestyle_tags"],
                    core_scenarios=demo["core_scenarios"],
                    source_type="manual",
                )
                db.add(td)

        # 4. Product Strategy
        prod = data.get("product_strategy")
        if prod:
            existing = db.query(ProductStrategy).filter(ProductStrategy.brand_id == brand.id).first()
            if not existing:
                pstrat = ProductStrategy(
                    brand_id=brand.id,
                    hero_products=prod["hero_products"],
                    launch_cadence=prod["launch_cadence"],
                    sku_count_estimate=prod["sku_count_estimate"],
                    has_sustainable_line=prod["has_sustainable_line"],
                    collab_strategy=prod.get("collab_strategy"),
                    recent_collabs=prod.get("recent_collabs") or [],
                    tech_innovations=prod["tech_innovations"],
                    category_expansion=prod.get("category_expansion") or [],
                    data_as_of=date(2026, 7, 1),
                    source_type="manual",
                )
                db.add(pstrat)

        # 5. Channel Strategy
        chan = data.get("channel_strategy")
        if chan:
            existing = db.query(ChannelStrategy).filter(ChannelStrategy.brand_id == brand.id).first()
            if not existing:
                cs = ChannelStrategy(
                    brand_id=brand.id,
                    dtc_pct=chan["dtc_pct"],
                    wholesale_pct=chan["wholesale_pct"],
                    own_stores_na=chan["own_stores_na"],
                    retail_partners=chan["retail_partners"],
                    ecommerce_platforms=chan["ecommerce_platforms"],
                    international_markets=chan.get("international_markets") or [],
                    data_as_of=date(2026, 7, 1),
                    source_type="manual",
                )
                db.add(cs)

        # 6. Social Media Metrics
        social_list = data.get("social_media", [])
        for sm in social_list:
            existing = db.query(SocialMediaMetrics).filter(
                SocialMediaMetrics.brand_id == brand.id,
                SocialMediaMetrics.platform == sm["platform"],
            ).first()
            if not existing:
                smm = SocialMediaMetrics(
                    brand_id=brand.id,
                    platform=sm["platform"],
                    followers=sm["followers"],
                    engagement_rate=sm["engagement_rate"],
                    avg_likes=sm["avg_likes"],
                    avg_comments=sm["avg_comments"],
                    post_frequency=sm["post_frequency"],
                    top_hashtags=sm.get("top_hashtags"),
                    key_kols=sm.get("key_kols"),
                    data_as_of=date(2026, 7, 1),
                    source_type="manual",
                )
                db.add(smm)

        # 7. Digital Capability
        dig = data.get("digital")
        if dig:
            existing = db.query(DigitalCapability).filter(DigitalCapability.brand_id == brand.id).first()
            if not existing:
                dc = DigitalCapability(
                    brand_id=brand.id,
                    monthly_web_visits=dig["monthly_web_visits"],
                    app_rating=dig.get("app_rating"),
                    app_downloads=dig.get("app_downloads"),
                    has_personalization=dig["has_personalization"],
                    has_virtual_tryon=dig["has_virtual_tryon"],
                    has_community_feature=dig["has_community_feature"],
                    has_membership_program=dig["has_membership_program"],
                    membership_name=dig.get("membership_name"),
                    ai_features=dig.get("ai_features") or [],
                    data_as_of=date(2026, 7, 1),
                    source_type="manual",
                )
                db.add(dc)

        # 8. Financial Performance
        fin_list = data.get("financials", [])
        for fin in fin_list:
            existing = db.query(FinancialPerformance).filter(
                FinancialPerformance.brand_id == brand.id,
                FinancialPerformance.fiscal_year == fin["fiscal_year"],
            ).first()
            if not existing:
                fp = FinancialPerformance(
                    brand_id=brand.id,
                    fiscal_year=fin["fiscal_year"],
                    revenue=fin["revenue"],
                    revenue_growth_pct=fin["revenue_growth_pct"],
                    gross_margin_pct=fin["gross_margin_pct"],
                    na_revenue_pct=fin["na_revenue_pct"],
                    is_estimated=fin.get("is_estimated", False),
                    data_source=fin.get("data_source"),
                )
                db.add(fp)

        # 9. Customer Sentiment
        sent_list = data.get("sentiment", [])
        for sent in sent_list:
            existing = db.query(CustomerSentiment).filter(
                CustomerSentiment.brand_id == brand.id,
                CustomerSentiment.platform == sent["platform"],
            ).first()
            if not existing:
                cs = CustomerSentiment(
                    brand_id=brand.id,
                    platform=sent["platform"],
                    rating=sent["rating"],
                    review_count=sent["review_count"],
                    positive_themes=sent["positive_themes"],
                    negative_themes=sent["negative_themes"],
                    nps_score=sent.get("nps_score"),
                    data_as_of=date(2026, 7, 1),
                    source_type="manual",
                )
                db.add(cs)

        # 10. Competitive Events
        events_list = data.get("events", [])
        for evt in events_list:
            existing = db.query(CompetitiveEvent).filter(
                CompetitiveEvent.brand_id == brand.id,
                CompetitiveEvent.title == evt["title"],
            ).first()
            if not existing:
                ce = CompetitiveEvent(
                    brand_id=brand.id,
                    event_type=evt["event_type"],
                    title=evt["title"],
                    description=evt.get("description"),
                    event_date=date.fromisoformat(evt["event_date"]),
                    importance=evt.get("importance", "medium"),
                    tags=evt.get("tags"),
                )
                db.add(ce)


def main():
    # Ensure tables exist
    print("创建数据库表...")
    Base.metadata.create_all(bind=engine)

    db = SessionLocal()
    try:
        print("=== 开始种子数据填充（数据更新至 2026-07-01） ===")

        print("1/3 创建分类体系...")
        cat_map = seed_categories(db)
        db.commit()
        print(f"  创建/确认 {len(cat_map)} 个分类")

        print("2/3 创建品牌数据...")
        brand_map = seed_brands(db, cat_map)
        db.commit()
        print(f"  创建/确认 {len(brand_map)} 个品牌")

        print("3/3 填充维度数据...")
        seed_dimension_data(db, brand_map)
        db.commit()
        print("  完成所有维度数据填充")

        print("\n=== 种子数据填充完成 ===")
        print(f"共处理 {len(BRANDS_DATA)} 个品牌")
        print("数据覆盖范围: 财务 2022-2025 | 事件 2024-2026 | 社媒 2026-07")

    except Exception as e:
        db.rollback()
        print(f"错误: {e}")
        raise
    finally:
        db.close()


if __name__ == "__main__":
    main()
